const STATUS_CONFIG = {
  'Booked': {
    pillKey: 'booked',
    badgeClass: 'b-booked'
  },
  'Booking In': {
    pillKey: 'booking-in',
    badgeClass: 'b-booking-in'
  },
  'Booked In': {
    pillKey: 'booked-in',
    badgeClass: 'b-booked-in'
  },
  'Collected': {
    pillKey: 'collected',
    badgeClass: 'b-collected'
  },
  'Received': {
    pillKey: 'received',
    badgeClass: 'b-received'
  },
  'Processing/Pricing': {
    pillKey: 'processing',
    badgeClass: 'b-processing'
  },
  'Complete': {
    pillKey: 'complete',
    badgeClass: 'b-complete'
  },
  'Booking complete': {
    pillKey: 'booking-complete',
    badgeClass: 'b-booking-complete'
  }
};
const STATUS_ORDER = Object.keys(STATUS_CONFIG);
let allData = [];
let activeStatus = 'All';
function initData() {
  const model = appsmith.model || {};
  allData = Array.isArray(model.collections) ? model.collections : [];
  applyFilters();
}
function buildPills() {
  const container = document.getElementById('filterPills');
  const presentStatuses = STATUS_ORDER.filter(s => allData.some(r => r.status === s));
  let html = '<span class="pill ' + (activeStatus === 'All' ? 'active-all' : '') + '" onclick="setFilter(\'All\')">All <span class="cnt">' + allData.length + '</span></span>';
  presentStatuses.forEach(function (s) {
    const cfg = STATUS_CONFIG[s];
    const count = allData.filter(r => r.status === s).length;
    const isActive = activeStatus === s ? 'active-' + cfg.pillKey : '';
    html += '<span class="pill ' + isActive + '" onclick="setFilter(\'' + s.replace(/'/g, "\\'") + '\')">' + s + ' <span class="cnt">' + count + '</span></span>';
  });
  container.innerHTML = html;
}
function renderTable(data) {
  const tbody = document.getElementById('tableBody');
  const noResults = document.getElementById('noResults');
  if (!data.length) {
    tbody.innerHTML = '';
    noResults.style.display = 'block';
    return;
  }
  noResults.style.display = 'none';
  tbody.innerHTML = data.map(function (row) {
    const customer = row.customer_name || '';
    const address = row.address1 || '';
    const date = row.collection_date || '';
    const status = row.status || '';
    const id = row.collection_id || row.id;
    const badgeClass = (STATUS_CONFIG[status] || {
      badgeClass: 'b-default'
    }).badgeClass;
    return '<tr class="data-row">' + '<td title="' + escHtml(customer) + '">' + escHtml(customer) + '</td>' + '<td title="' + escHtml(address) + '">' + escHtml(address) + '</td>' + '<td>' + escHtml(date) + '</td>' + '<td><span class="badge ' + badgeClass + '">' + escHtml(status) + '</span></td>' + '<td class="td-goto"><button class="goto-btn" onclick="goToCollection(' + JSON.stringify(id) + ')" aria-label="Go to collection">' + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">' + '<line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>' + '</button></td></tr>';
  }).join('');
}
function escHtml(str) {
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
window.setFilter = function (status) {
  activeStatus = status;
  window.applyFilters();
};
window.applyFilters = function () {
  const q = (document.getElementById('searchInput').value || '').toLowerCase();
  let filtered = allData;
  if (activeStatus !== 'All') filtered = filtered.filter(r => r.status === activeStatus);
  if (q) {
    filtered = filtered.filter(r => (r.customer_name || '').toLowerCase().includes(q) || (r.address1 || '').toLowerCase().includes(q) || (r.collection_date || '').toLowerCase().includes(q) || (r.status || '').toLowerCase().includes(q));
  }
  buildPills();
  renderTable(filtered);
};
window.goToCollection = function (id) {
  appsmith.updateModel({
    collectionId: id
  });
  appsmith.triggerEvent('onGoTo');
};
appsmith.onReady(function () {
  initData();
  appsmith.onModelChange(initData);
});

